(function () {
  "use strict";

  var TEMPLATE_ID = window.TEMPLATE_ID;
  var PREVIEW_DPI = 150;          // matches the server-side renderer
  var POINT_PER_INCH = 72;        // PDF native
  var PREVIEW_PX_PER_PT = PREVIEW_DPI / POINT_PER_INCH;  // 150/72 ≈ 2.083

  var template = null;            // { id, name, form_fields, signature_zones, ... }
  var fields = [];                // array of FormField
  var zones = [];                 // array of SignatureZone
  var currentPage = 1;
  var pageCount = 1;
  var pageNaturalSize = { w: 0, h: 0 };  // image natural pixels
  var pagePtSize = { w: 0, h: 0 };       // PDF point dims = naturalPx / scale
  var mode = "field";              // 'field' | 'signature'
  var selectedItem = null;         // { kind: 'field'|'zone', id: string }
  var drag = null;                 // { id, kind, dx, dy }

  var $title = document.querySelector("[data-template-name]");
  var $canvas = document.querySelector("[data-editor-canvas]");
  var $preview = document.querySelector("[data-editor-preview]");
  var $overlay = document.querySelector("[data-editor-overlay]");
  var $hint = document.querySelector("[data-editor-hint]");
  var $fieldsList = document.querySelector("[data-fields-list]");
  var $zonesList = document.querySelector("[data-zones-list]");
  var $pageCur = document.querySelector("[data-page-current]");
  var $pageTot = document.querySelector("[data-page-total]");
  var $propsPane = document.querySelector("[data-properties-pane]");
  var $propLabel = document.querySelector("[data-prop-label]");
  var $propTypeGroup = document.querySelector("[data-prop-type-group]");
  var $propType = document.querySelector("[data-prop-type]");
  var $propOptionsGroup = document.querySelector("[data-prop-options-group]");
  var $propOptions = document.querySelector("[data-prop-options]");
  var $propRequiredGroup = document.querySelector("[data-prop-required-group]");
  var $propRequired = document.querySelector("[data-prop-required]");
  var $editorError = document.querySelector("[data-editor-error]");

  async function api(method, url, body) {
    var init = { method: method, headers: { "Accept": "application/json", "X-Requested-With": "XMLHttpRequest" } };
    if (body !== undefined) {
      init.headers["Content-Type"] = "application/json";
      init.body = JSON.stringify(body);
    }
    var r = await fetch(url, init);
    if (r.status === 204) return null;
    var data = null;
    try { data = await r.json(); } catch (_e) {}
    if (!r.ok) {
      var msg = (data && (data.detail || data.message)) || ("שגיאה " + r.status);
      throw { status: r.status, code: (data && data.code) || null, message: msg };
    }
    return data;
  }

  function showError(text) { $editorError.textContent = text; $editorError.classList.remove("org-hidden"); }
  function hideError() { $editorError.textContent = ""; $editorError.classList.add("org-hidden"); }

  function nextId(prefix) {
    return prefix + "_" + Math.random().toString(36).slice(2, 8);
  }

  function clamp(n, lo, hi) { return Math.max(lo, Math.min(hi, n)); }

  function pxToPt(px, axis) {

    var rect = $overlay.getBoundingClientRect();
    var displayedPx = axis === "x" ? rect.width : rect.height;
    var naturalPx = axis === "x" ? pageNaturalSize.w : pageNaturalSize.h;
    if (!displayedPx || !naturalPx) return px;
    return (px * (naturalPx / displayedPx)) / PREVIEW_PX_PER_PT;
  }

  function ptToPx(pt, axis) {
    var rect = $overlay.getBoundingClientRect();
    var displayedPx = axis === "x" ? rect.width : rect.height;
    var naturalPx = axis === "x" ? pageNaturalSize.w : pageNaturalSize.h;
    if (!displayedPx || !naturalPx) return pt;
    return pt * PREVIEW_PX_PER_PT * (displayedPx / naturalPx);
  }

  async function boot() {
    try {
      template = await api("GET", "/org/api/document-templates/" + TEMPLATE_ID);
      $title.textContent = template.name;
      fields = (template.form_fields || []).map(function (f) { return Object.assign({}, f); });
      zones = (template.signature_zones || []).map(function (z) { return Object.assign({}, z); });
      if (template.uploaded_file_type !== "PDF") {
        showError("סימון שדות זמין כרגע ל-PDF בלבד. ה-DOCX יישלח כפי שהוא.");
      }
      await loadPagePreview(1);
      renderItemsList();
      renderOverlay();
    } catch (e) {
      showError(e.message || "טעינה נכשלה");
    }
  }

  function loadPagePreview(page) {
    return new Promise(function (resolve) {
      $hint.textContent = "טוען עמוד " + page + "…";
      $preview.onload = function () {
        pageNaturalSize = { w: $preview.naturalWidth, h: $preview.naturalHeight };
        pagePtSize = {
          w: pageNaturalSize.w / PREVIEW_PX_PER_PT,
          h: pageNaturalSize.h / PREVIEW_PX_PER_PT,
        };
        $hint.textContent = "";
        $pageCur.textContent = String(currentPage);

        if (!$pageTot.textContent || $pageTot.textContent === "?") {
          $pageTot.textContent = "?";
        }
        renderOverlay();
        resolve();
      };

      $preview.src = "/org/api/document-templates/" + TEMPLATE_ID +
        "/preview?page=" + page + "&_=" + Date.now();
    });
  }

  function gotoPage(n) {
    n = Math.max(1, n);
    currentPage = n;
    selectedItem = null;
    $propsPane.hidden = true;
    loadPagePreview(n);
  }

  function renderOverlay() {
    $overlay.replaceChildren();

    fields.filter(function (f) { return f.page === currentPage; }).forEach(function (f) {
      $overlay.appendChild(makeBox(f, "field"));
    });
    zones.filter(function (z) { return z.page === currentPage; }).forEach(function (z) {
      $overlay.appendChild(makeBox(z, "zone"));
    });
  }

  function makeBox(item, kind) {
    var box = document.createElement("div");
    box.className = "org-template-editor__box org-template-editor__box--" + kind +
      (selectedItem && selectedItem.id === item.id ? " is-selected" : "");
    box.dataset.itemId = item.id;
    box.dataset.itemKind = kind;
    box.style.insetInlineStart = ptToPx(item.x, "x") + "px";
    box.style.insetBlockStart = ptToPx(item.y, "y") + "px";
    box.style.width = ptToPx(item.width, "x") + "px";
    box.style.height = ptToPx(item.height, "y") + "px";

    var label = document.createElement("span");
    label.className = "org-template-editor__box-label";
    label.textContent = item.label || (kind === "zone" ? "חתימה" : "שדה");
    box.appendChild(label);
    return box;
  }

  function renderItemsList() {

    if (fields.length === 0) {
      $fieldsList.replaceChildren(makeEmpty("אין שדות עדיין. לחץ על המסמך כדי להוסיף."));
    } else {
      $fieldsList.replaceChildren.apply($fieldsList, fields.map(function (f) {
        return makeListItem(f, "field");
      }));
    }

    if (zones.length === 0) {
      $zonesList.replaceChildren(makeEmpty("אין אזורי חתימה."));
    } else {
      $zonesList.replaceChildren.apply($zonesList, zones.map(function (z) {
        return makeListItem(z, "zone");
      }));
    }
  }

  function makeEmpty(text) {
    var li = document.createElement("li");
    li.className = "org-text-sm org-text-muted";
    li.textContent = text;
    return li;
  }

  function makeListItem(item, kind) {
    var li = document.createElement("li");
    li.className = "org-template-editor__list-item" +
      (selectedItem && selectedItem.id === item.id ? " is-selected" : "");
    li.dataset.itemId = item.id;
    li.dataset.itemKind = kind;
    var name = document.createElement("strong");
    name.textContent = item.label || (kind === "zone" ? "חתימה" : "שדה");
    var meta = document.createElement("span");
    meta.className = "org-text-sm org-text-muted";
    meta.textContent = " · עמוד " + item.page + (item.type ? " · " + item.type : "");
    li.appendChild(name);
    li.appendChild(meta);
    return li;
  }

  function selectItem(kind, id) {
    selectedItem = { kind: kind, id: id };
    var item = findItem(kind, id);
    if (!item) {
      $propsPane.hidden = true;
      return;
    }
    $propLabel.value = item.label || "";
    if (kind === "field") {
      $propTypeGroup.hidden = false;
      $propType.value = item.type || "text";
      $propRequiredGroup.hidden = false;
      $propRequired.checked = !!item.required;
      $propOptionsGroup.hidden = item.type !== "select";
      $propOptions.value = (item.options || []).join(", ");
    } else {
      $propTypeGroup.hidden = true;
      $propRequiredGroup.hidden = true;
      $propOptionsGroup.hidden = true;
    }
    $propsPane.hidden = false;
    renderOverlay();
    renderItemsList();
  }

  function findItem(kind, id) {
    var list = kind === "field" ? fields : zones;
    for (var i = 0; i < list.length; i++) {
      if (list[i].id === id) return list[i];
    }
    return null;
  }

  function deleteSelected() {
    if (!selectedItem) return;
    var list = selectedItem.kind === "field" ? fields : zones;
    for (var i = 0; i < list.length; i++) {
      if (list[i].id === selectedItem.id) {
        list.splice(i, 1);
        break;
      }
    }
    selectedItem = null;
    $propsPane.hidden = true;
    renderOverlay();
    renderItemsList();
  }

  $overlay.addEventListener("pointerdown", function (e) {

    if (e.target !== $overlay) return;
    var rect = $overlay.getBoundingClientRect();
    var px = e.clientX - rect.left;
    var py = e.clientY - rect.top;
    var ptX = clamp(pxToPt(px, "x"), 0, pagePtSize.w);
    var ptY = clamp(pxToPt(py, "y"), 0, pagePtSize.h);

    if (mode === "field") {
      var f = {
        id: nextId("f"),
        type: "text",
        label: "שדה",
        required: false,
        x: Math.round(ptX),
        y: Math.round(ptY),
        width: 200,
        height: 30,
        page: currentPage,
      };
      fields.push(f);
      selectItem("field", f.id);
    } else {
      var z = {
        id: nextId("s"),
        label: "חתימה",
        x: Math.round(ptX),
        y: Math.round(ptY),
        width: 240,
        height: 80,
        page: currentPage,
      };
      zones.push(z);
      selectItem("zone", z.id);
    }
  });

  $overlay.addEventListener("pointerdown", function (e) {
    var box = e.target.closest("[data-item-id]");
    if (!box || box === $overlay) return;
    e.stopPropagation();
    var id = box.dataset.itemId;
    var kind = box.dataset.itemKind;
    selectItem(kind, id);

    var item = findItem(kind, id);
    if (!item) return;
    var rect = $overlay.getBoundingClientRect();
    drag = {
      id: id,
      kind: kind,

      dx: (e.clientX - rect.left) - ptToPx(item.x, "x"),
      dy: (e.clientY - rect.top) - ptToPx(item.y, "y"),
    };
    $overlay.setPointerCapture(e.pointerId);
  });

  $overlay.addEventListener("pointermove", function (e) {
    if (!drag) return;
    var item = findItem(drag.kind, drag.id);
    if (!item) return;
    var rect = $overlay.getBoundingClientRect();
    var px = e.clientX - rect.left - drag.dx;
    var py = e.clientY - rect.top - drag.dy;
    item.x = Math.round(clamp(pxToPt(px, "x"), 0, pagePtSize.w - item.width));
    item.y = Math.round(clamp(pxToPt(py, "y"), 0, pagePtSize.h - item.height));
    renderOverlay();
  });

  $overlay.addEventListener("pointerup", function () {
    if (drag) {
      drag = null;
      renderItemsList();
    }
  });

  $propLabel.addEventListener("input", function () {
    if (!selectedItem) return;
    var item = findItem(selectedItem.kind, selectedItem.id);
    if (item) {
      item.label = $propLabel.value;
      renderOverlay();
      renderItemsList();
    }
  });
  $propType.addEventListener("change", function () {
    if (!selectedItem || selectedItem.kind !== "field") return;
    var item = findItem("field", selectedItem.id);
    if (item) {
      item.type = $propType.value;
      $propOptionsGroup.hidden = item.type !== "select";
      renderItemsList();
    }
  });
  $propRequired.addEventListener("change", function () {
    if (!selectedItem || selectedItem.kind !== "field") return;
    var item = findItem("field", selectedItem.id);
    if (item) item.required = $propRequired.checked;
  });
  $propOptions.addEventListener("input", function () {
    if (!selectedItem || selectedItem.kind !== "field") return;
    var item = findItem("field", selectedItem.id);
    if (item) {
      item.options = $propOptions.value.split(",").map(function (s) { return s.trim(); }).filter(Boolean);
    }
  });

  document.addEventListener("click", function (e) {
    var t = e.target.closest("[data-action], [data-mode]");
    if (!t) return;
    if (t.dataset.mode) {
      mode = t.dataset.mode;
      document.querySelectorAll("[data-mode]").forEach(function (btn) {
        btn.classList.toggle("is-active", btn.dataset.mode === mode);
      });
      return;
    }
    if (t.dataset.action === "page-prev") return gotoPage(currentPage - 1);
    if (t.dataset.action === "page-next") return gotoPage(currentPage + 1);
    if (t.dataset.action === "delete-item") return deleteSelected();
    if (t.dataset.action === "save-fields") return saveFields();
  });

  document.addEventListener("click", function (e) {
    var li = e.target.closest("[data-item-kind]");
    if (!li || li.tagName !== "LI") return;
    var kind = li.dataset.itemKind;
    var id = li.dataset.itemId;
    var item = findItem(kind, id);
    if (item && item.page !== currentPage) {

      currentPage = item.page;
      loadPagePreview(currentPage).then(function () { selectItem(kind, id); });
    } else {
      selectItem(kind, id);
    }
  });

  async function saveFields() {
    hideError();
    try {
      await api("PATCH", "/org/api/document-templates/" + TEMPLATE_ID + "/fields", {
        form_fields: fields,
        signature_zones: zones,
      });
      window.OrgToast && window.OrgToast.show("השדות נשמרו, חוזר לרשימת המסמכים", "success");

      setTimeout(function () {
        window.location.href = "/org/document-templates";
      }, 600);
    } catch (e) {
      showError(e.message);
    }
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", boot);
  } else {
    boot();
  }
})();